const RED = '#C8181E';
const BLACK = '#1a1a1a';
const DARK = '#333333';
const GRAY = '#666666';
const LGRAY = '#f2f2f2';
const MGRAY = '#bbbbbb';
const WHITE = '#ffffff';

const abs = (p) => {
  if (!p) return null;
  if (p.startsWith('http') || p.startsWith('data:')) return p;
  if (typeof window !== 'undefined') return window.location.origin + '/' + p.replace(/^\//, '');
  return null;
};

const fmtDate = (d) => {
  if (!d) {
    const now = new Date();
    return `${String(now.getDate()).padStart(2, '0')}/${String(now.getMonth() + 1).padStart(2, '0')}/${now.getFullYear()}`;
  }
  return d;
};

const SafeImage = ({ src, style }) => {
  if (!src || typeof src !== 'string') return null;
  return <Image src={src} style={style} />;
};

const fmtINR = (n) => {
  if (!n && n !== 0) return '';
  return 'INR ' + Number(n).toLocaleString('en-IN') + '/-';
};

const fmtUSD = (n) => {
  if (!n && n !== 0) return '';
  return 'US$ ' + Number(n).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

