// =============================================================================
// ATOMS
// =============================================================================
// LH uses hardcoded LETTERHEAD_B64 by default; pass override via letterheadB64 prop
const LH = ({ letterheadB64 }) => {
  const src = letterheadB64 || LETTERHEAD_B64 || null;
  if (!src) return null;
  return <Image src={src} style={S.lhBg} fixed />;
};

const PgNo = () => (
  <Text style={S.pgNo}
    render={({ pageNumber, totalPages }) => `Page ${pageNumber} of ${totalPages}`}
    fixed />
);

const SecHead = ({ title }) => (
  <View style={S.secWrap}>
    <Text style={S.secTxt}>{title}</Text>
  </View>
);

const SpecTable = ({ specs }) => {
  const rows = Object.entries(specs);
  return (
    <View style={S.tbl}>
      <View style={S.tblHead}>
        <View style={S.tblC1}><Text style={S.tblHd}>Subject</Text></View>
        <View style={S.tblC2}><Text style={S.tblHd}>Description</Text></View>
      </View>
      {rows.map(([k, v], i) => (
        <View key={i} style={i === rows.length - 1 ? S.tblRowLast : S.tblRow}>
          <View style={S.tblC1}><Text style={S.tblCell}>{k}</Text></View>
          <View style={S.tblC2}><Text style={S.tblCell}>{String(v)}</Text></View>
        </View>
      ))}
    </View>
  );
};

// =============================================================================
// PAGE 1: COVER
// =============================================================================
const CoverPage = ({ customer, machine, pricing, letterheadB64 }) => {
  const company = (customer.company_name || customer.company || 'VALUED CUSTOMER').toUpperCase();
  const city = [customer.city, customer.state].filter(Boolean).join(', ').toUpperCase();
  const imgSrc = abs(machine.image);
  const p = pricing || {};
  const isUSD = (p.currency || 'INR') === 'USD';
  const showPrice = p.show_price !== false && (p.basic_price_inr || p.basic_price_usd);

  // Build the machine title line:
  // e.g. "AE Innoflex THREE LAYER CO EXTRUSION BLOWN FILM LINE 2370_75*90*75"
  const machineTypeLine = machine.title_line || machine.type || '';

  return (
    <Page size="A4" style={S.page}>
      <LH letterheadB64={letterheadB64} />
      <View style={S.zone}>
        <View style={S.coverWrap}>
          {/* Only show machine photo if image is explicitly provided */}
          {!!imgSrc && <SafeImage src={imgSrc} style={S.coverMachImg} />}

          <Text style={S.coverProposal}>PROPOSAL OF</Text>

          {/* AE [red]Innoflex[/red] THREE LAYER CO EXTRUSION BLOWN FILM LINE 2370_75*90*75 */}
          <View style={S.coverLine2}>
            <Text style={S.coverAE}>AE </Text>
            <Text style={S.coverRed}>Innoflex </Text>
            <Text style={S.coverAE}>{machineTypeLine}</Text>
          </View>

          <Text style={S.coverFOR}>FOR</Text>
          <Text style={S.coverCustomer}>M/s. {company}</Text>
          {!!city && <Text style={S.coverCity}>{city}</Text>}
        </View>

        {/* Pricing block — only shown when show_price is not false */}
        {showPrice && (
          <View style={S.coverPriceWrap}>
            <View style={S.priceLine}>
              <Text style={S.priceBullet}>{'❖ BASIC PRICE ' + (p.price_label || 'EX-WORKS, UNPACKED') + ' '}</Text>
              <Text style={S.priceDots}>{'..................... '}</Text>
              <Text style={S.priceAmount}>
                {isUSD ? fmtUSD(p.basic_price_usd) : fmtINR(p.basic_price_inr)}
              </Text>
            </View>
            {p.basic_price_words && (
              <Text style={S.priceWords}>{'(' + p.basic_price_words + ')'}</Text>
            )}
            {(p.final_price_inr || p.final_price_usd) && (
              <View style={S.priceLine}>
                <Text style={S.priceBullet}>{'FINAL PRICE AFTER DISCOUNT.......... '}</Text>
                <Text style={S.priceAmount}>
                  {isUSD ? fmtUSD(p.final_price_usd) : fmtINR(p.final_price_inr)}
                </Text>
              </View>
            )}
          </View>
        )}
        <PgNo />
      </View>
    </Page>
  );
};

// =============================================================================
// PAGE 2: SCOPE OF SUPPLY
