export const MasterQuotationPDF = ({ data }) => {
  if (!data) data = DEFAULT_DATA;

  const letterheadB64 = data.letterhead_b64 || null;
  const customer = data.customer || {};
  const machine = data.machine || {};
  const quot = data.quotation || {};
  const scope = data.scope || [];
  const pricing = data.pricing || {};
  const components = data.components || [];
  const optionalItems = data.optional_items || data.optionalItems || [];
  const allItems = [...components, ...optionalItems];
  const performance = data.performance;
  const utilities = data.utilities;
  const siteServices = data.site_services;
  const electricals = data.electricals;
  const optionalAddons = data.optional_addons || [];
  const signatoryName = data.signatory_name || 'Authorised Signatory';
  const showTerms = data.show_terms !== false;

  // Show electricals page only if data or optional addons exist
  const showElec = !!(
    electricals ||
    optionalAddons.length > 0
  );

  const refNo = quot.ref_no || quot.refNo || 'DRAFT';
  const date = fmtDate(quot.date);

  return (
    <Document
      title={`Proposal – ${customer.company_name || customer.company || 'Customer'}`}
      author="Adroit Extrusion"
      subject="Blown Film Line Proposal"
    >
      {/* 1. Cover */}
      <CoverPage
        customer={customer}
        machine={machine}
        pricing={pricing}
        letterheadB64={letterheadB64}
      />

      {/* 2. Scope of Supply (Ref/Date on this page ONLY) */}
      {scope.length > 0 && (
        <ScopePage
          scope={scope}
          pricing={pricing}
          refNo={refNo}
          date={date}
          letterheadB64={letterheadB64}
        />
      )}

      {/* 3+. Component detail pages */}
      {allItems.map((item, idx) => (
        <ComponentPage
          key={idx}
          item={item}
          index={idx}
          showAnnexureHeader={idx === 0}
          letterheadB64={letterheadB64}
        />
      ))}

      {/* Indicative Performance */}
      {performance && (
        <PerformancePage performance={performance} letterheadB64={letterheadB64} />
      )}

      {/* Items Not Included + Utilities + Power Table */}
      <UtilitiesPage utilities={utilities} letterheadB64={letterheadB64} />

      {/* Water + Air + Environment */}
      <SiteServicesPage siteServices={siteServices} letterheadB64={letterheadB64} />

      {/* Electricals + Tower + Optional Equipment */}
      {showElec && (
        <ElectricalsPage
          electricals={electricals}
          optionalAddons={optionalAddons}
          letterheadB64={letterheadB64}
        />
      )}

      {/* Terms & Conditions */}
      {showTerms && (
        <TermsPage
          signatoryName={signatoryName}
          letterheadB64={letterheadB64}
        />
      )}

      {/* Standard Warranty Terms */}
      {showTerms && <WarrantyPage letterheadB64={letterheadB64} />}
    </Document>
  );
};

// =============================================================================
// PRE-VALIDATION HELPER
// Strip out 404 image paths before rendering to avoid PDF generation errors.
// Usage:
//   const cleanData = await prevalidateImages(rawData);
//   const blob = await pdf(<MasterQuotationPDF data={cleanData} />).toBlob();
// =============================================================================
const checkImg = async (url) => {
  if (!url) return false;
  if (url.startsWith('data:')) return true;
  try {
    const r = await fetch(url, { method: 'HEAD' });
    return r.ok;
  } catch {
    return false;
  }
};

export const prevalidateImages = async (data) => {
  if (!data) return data;
  const d = { ...data };

  if (d.machine?.image) {
    const src = abs(d.machine.image);
    const ok = await checkImg(src);
    d.machine = { ...d.machine, image: ok ? d.machine.image : null };
  }

  const validateItems = async (items) => {
    if (!items?.length) return items;
    return Promise.all(items.map(async (item) => {
      if (!item.image) return item;
      const src = abs(item.image);
      const ok = await checkImg(src);
      return { ...item, image: ok ? item.image : null };
    }));
  };

  d.components = await validateItems(d.components);
  d.optional_items = await validateItems(d.optional_items || d.optionalItems || []);

  return d;
};

