/**
 * Build a scope row.
 * buildScopeRow(1, "Three Nos. Extruders of 75/90/75 mm ...")
 */
export const buildScopeRow = (sr, description) => ({ sr, description });

/**
 * Build a component spec entry.
 * buildComponent("Extruder 75 mm (Co-ex – Long)", "/images/ext75.jpg", {
 *   "Screw Diameter": "75 mm single screw ...",
 *   "L/D ratio": "32:1",
 *   ...
 * })
 */
export const buildComponent = (name, image, techDesc) => ({
  name,
  image: image || null,
  tech_desc: techDesc || {},
});

/**
 * Build a power table row.
 * buildPowerRow(1, "EXTRUDER 75 MM", 2, 18.4, 75)
 */
export const buildPowerRow = (sr, equipment, qty, heating_kw, motive_kw) => ({
  sr, equipment, qty, heating_kw, motive_kw,
});

/**
 * Build an air consumption row.
 * buildAirRow(1, "AT DIE DURING STARTUP & OPERATION", 1, "5-7 BAR", 8.5)
 */
export const buildAirRow = (sr, equipment, qty, pressure, air_m3hr) => ({
  sr, equipment, qty, pressure, air_m3hr,
});

